class Solution {
    public long smallestNumber(long num) {
        if (num == 0) return 0;
        boolean isNegative = num < 0;
        num = Math.abs(num);
        long[] digits = new long[(int) Math.floor(Math.log10(num)) + 1];
        int index = 0;
        while (num > 0) {
            digits[index++] = num % 10;
            num /= 10;
        }
        Arrays.sort(digits);
        if (isNegative) digits[0] = -1 * digits[0];
        for (int i = 0; i < digits.length; i++) {
            num = num * 10 + digits[i];
        }
        return num;
    }
}
